import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';
import { Vex } from 'vex-sdk';

const bedrock = new BedrockAgentRuntimeClient({ region: 'us-east-1' });
const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

const command = new InvokeAgentCommand({
  agentId: 'YOUR_AGENT_ID',
  agentAliasId: 'YOUR_ALIAS_ID',
  sessionId: 'session-123',
  inputText: 'What\'s the price of iPhone 15?'
});

const response = await bedrock.send(command);
const completion = response.completion;

const result = await vex.verify({
  input: completion,
  policy: 'ecommerce-pricing-accuracy',
  context: {
    product_sku: 'IPH15-128GB',
    listed_price: 799.00,
    session_history: sessionHistory
  }
});

if (result.status === 'pass') {
  return completion;
} else {
  throw new Error('Pricing violation detected');
}
